def reverse_list(lst):
    if len(lst) == 0:
        return []
    return [lst[-1]] + reverse_list(lst[:-1])

input_line = input().split()
numbers = []
for x in input_line:
    numbers.append(int(x))
reversed_numbers = reverse_list(numbers)
output = ""
for x in reversed_numbers:
    output = output + str(x) + " "
print(output.strip())
